node -e "
const db = require('better-sqlite3')('/workspace/vibers/.nexus/nexus.db');
const id = 'w-mnt106rv-94bed1e0ace3';
const newParent = 'w-mnswvmj7-2112b86f710a';

// verify the new parent exists and is a quest
const parentRow = db.prepare('SELECT content FROM books_clerk_writs WHERE id = ?').get(newParent);
if (!parentRow) { console.error('new parent not found'); process.exit(1); }
const parent = JSON.parse(parentRow.content);
console.log('New parent:', parent.id, '—', parent.title, '[' + parent.type + '/' + parent.status + ']');

// load, mutate, write back
const row = db.prepare('SELECT content FROM books_clerk_writs WHERE id = ?').get(id);
const content = JSON.parse(row.content);
const oldParent = content.parentId;
content.parentId = newParent;
content.updatedAt = new Date().toISOString();
const stmt = db.prepare('UPDATE books_clerk_writs SET content = ? WHERE id = ?');
const info = stmt.run(JSON.stringify(content), id);
console.log('Updated rows:', info.changes);
console.log('Re-parented', id, ':', oldParent, '→', newParent);

// verify
const check = JSON.parse(db.prepare('SELECT content FROM books_clerk_writs WHERE id = ?').get(id).content);
console.log('Verified parentId:', check.parentId);
" 2>&1

